DepolyerSol = '''
//pragma solidity ^0.5.10;

contract Deployer {
    bytes public deployBytecode;
    address public deployedAddr;
    function getAddr() view public returns(address) {
        return deployedAddr;
    }
    
    function deploy() public {
        //deployBytecode = serviceRtCode;
        bytes memory initCode = hex'';
        address a;
        assembly {
            a := create(callvalue, add(0x20, initCode), mload(initCode))
        }
        deployedAddr = a;
    }
}
'''

